#include<bits/stdc++.h>
#define ll long long
#define CI const int
#define PII pair<int,int>
using namespace std;
CI MAXN=2e5+5;
queue<int> q;
int n;
struct node
{
	int l,r,t;
}a[MAXN];
void Delete(int x)
{
	a[a[x].l].r=a[x].r;
	a[a[x].r].l=a[x].l;
}
int main(void){
	//freopen("xx.in","r",stdin);
	//freopen("xx.out","w",stdout);
	scanf("%d",&n);
	a[0].t=-1;
	a[n+1].t=-1;
	for(int i=1;i<=n;++i)
	{
		scanf("%d",&a[i].t);
		a[i].l=i-1;
		a[i].r=i+1;
	}
	for(int i=1;i<=n;++i)
	{
		if(a[i].t!=a[i-1].t)
		{
			q.push(i);
		}
	}
	while(!q.empty())
	{
		int len=q.size();
		for(int i=1;i<=len;++i)
		{
			int top=q.front();
			if(a[top].t==a[a[top].r].t&&a[a[top].r].t!=a[a[top].l].t)
			{
				q.push(a[top].r);
			}
			Delete(top);
			printf("%d ",top);
			q.pop();
		}puts("");
	}
	return false;
}
